308→func wordWrap(text string, width int) string {
309→	if width <= 0 {
310→		return text
311→	}
312→	var result strings.Builder
313→	for _, line := range strings.Split(text, "\n") {
314→		if len(line) <= width {
315→			result.WriteString(line + "\n")
316→			continue
317→		}
318→		remaining := line
319→		for len(remaining) > width {
320→			breakAt := width
321→			if idx := strings.LastIndex(remaining[:width], " "); idx > 0 {
322→				breakAt = idx
323→			}
324→			result.WriteString(remaining[:breakAt] + "\n")
325→			remaining = strings.TrimLeft(remaining[breakAt:], " ")
326→		}
327→		if remaining != "" {
328→			result.WriteString(remaining + "\n")
329→		}
330→	}
331→	return strings.TrimRight(result.String(), "\n")
332→}
